import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import axios from 'axios';
import styled from 'styled-components';
import { FaProjectDiagram, FaTasks, FaClipboardList, FaSignOutAlt, FaCalendarAlt, FaExclamationTriangle } from 'react-icons/fa';
import { format, isAfter, parseISO } from 'date-fns';

const Container = styled.div`
  min-height: 100vh;
  padding: 20px;
`;

const Header = styled.header`
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 40px;
`;

const Title = styled.h1`
  color: white;
  font-size: 32px;

  span {
    font-size: 16px;
    font-weight: normal;
    opacity: 0.8;
  }
`;

const LogoutBtn = styled.button`
  background: rgba(255, 255, 255, 0.2);
  color: white;
  padding: 10px 20px;
  border-radius: 10px;
  display: flex;
  align-items: center;
  gap: 8px;
  transition: background 0.3s;

  &:hover {
    background: rgba(255, 255, 255, 0.3);
  }
`;

const StatsGrid = styled.div`
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(250px, 1fr));
  gap: 20px;
  margin-bottom: 40px;
`;

const StatCard = styled.div`
  background: white;
  padding: 30px;
  border-radius: 20px;
  box-shadow: 0 10px 30px rgba(0, 0, 0, 0.1);
  display: flex;
  align-items: center;
  gap: 20px;
  transition: transform 0.3s;

  &:hover {
    transform: translateY(-5px);
  }
`;

const StatIcon = styled.div`
  width: 60px;
  height: 60px;
  border-radius: 15px;
  background: ${props => props.color};
  display: flex;
  align-items: center;
  justify-content: center;
  color: white;
  font-size: 24px;
`;

const StatInfo = styled.div``;

const StatValue = styled.h2`
  font-size: 36px;
  margin-bottom: 5px;
`;

const StatLabel = styled.p`
  color: #666;
`;

const Section = styled.section`
  background: white;
  padding: 30px;
  border-radius: 20px;
  box-shadow: 0 10px 30px rgba(0, 0, 0, 0.1);
  margin-bottom: 20px;
`;

const SectionTitle = styled.h2`
  margin-bottom: 20px;
  display: flex;
  align-items: center;
  gap: 10px;
`;

const TaskList = styled.div`
  display: flex;
  flex-direction: column;
  gap: 15px;
`;

const TaskItem = styled.div`
  display: flex;
  align-items: center;
  padding: 15px;
  background: #f8f9fa;
  border-radius: 10px;
  gap: 15px;
`;

const PriorityBadge = styled.span`
  padding: 5px 10px;
  border-radius: 5px;
  font-size: 12px;
  font-weight: 600;
  background: ${props => {
    if (props.priority === 'High') return '#fee2e2';
    if (props.priority === 'Medium') return '#fef3c7';
    return '#dcfce7';
  }};
  color: ${props => {
    if (props.priority === 'High') return '#dc2626';
    if (props.priority === 'Medium') return '#d97706';
    return '#16a34a';
  }};
`;

const StatusBadge = styled.span`
  padding: 5px 10px;
  border-radius: 5px;
  font-size: 12px;
  font-weight: 600;
  background: ${props => {
    if (props.status === 'Done') return '#dcfce7';
    if (props.status === 'InProgress') return '#dbeafe';
    return '#f3f4f6';
  }};
  color: ${props => {
    if (props.status === 'Done') return '#16a34a';
    if (props.status === 'InProgress') return '#2563eb';
    return '#4b5563';
  }};
`;

const NavLink = styled(Link)`
  display: inline-block;
  margin-top: 20px;
  color: #667eea;
  font-weight: 600;
`;

const Loading = styled.div`
  text-align: center;
  color: white;
  font-size: 24px;
`;

const Dashboard = () => {
  const { user, logout } = useAuth();
  const [tasks, setTasks] = useState([]);
  const [projects, setProjects] = useState([]);
  const [loading, setLoading] = useState(true);
  const [overdueCount, setOverdueCount] = useState(0);

  useEffect(() => {
    const fetchData = async () => {
      try {
        const [tasksRes, projectsRes] = await Promise.all([
          axios.get('/api/tasks'),
          axios.get('/api/projects')
        ]);
        setTasks(tasksRes.data);
        setProjects(projectsRes.data);

        // Calculate overdue tasks
        const overdue = tasksRes.data.filter(task =>
          task.dueDate && isAfter(new Date(), parseISO(task.dueDate)) && task.status !== 'Done'
        );
        setOverdueCount(overdue.length);
      } catch (error) {
        console.error('Error fetching data:', error);
      } finally {
        setLoading(false);
      }
    };
    fetchData();
  }, []);

  if (loading) return <Container><Loading>Loading...</Loading></Container>;

  const todoCount = tasks.filter(t => t.status === 'Todo').length;
  const inProgressCount = tasks.filter(t => t.status === 'InProgress').length;
  const doneCount = tasks.filter(t => t.status === 'Done').length;

  return (
    <Container>
      <Header>
        <Title>
          Team Task Manager
          <br />
          <span>Hello, {user?.name}!</span>
        </Title>
        <LogoutBtn onClick={logout}>
          <FaSignOutAlt /> Logout
        </LogoutBtn>
      </Header>

      <StatsGrid>
        <StatCard>
          <StatIcon color="#667eea">
            <FaProjectDiagram />
          </StatIcon>
          <StatInfo>
            <StatValue>{projects.length}</StatValue>
            <StatLabel>Projects</StatLabel>
          </StatInfo>
        </StatCard>
        <StatCard>
          <StatIcon color="#10b981">
            <FaTasks />
          </StatIcon>
          <StatInfo>
            <StatValue>{todoCount}</StatValue>
            <StatLabel>To Do</StatLabel>
          </StatInfo>
        </StatCard>
        <StatCard>
          <StatIcon color="#3b82f6">
            <FaClipboardList />
          </StatIcon>
          <StatInfo>
            <StatValue>{inProgressCount}</StatValue>
            <StatLabel>In Progress</StatLabel>
          </StatInfo>
        </StatCard>
        <StatCard>
          <StatIcon color={overdueCount > 0 ? "#ef4444" : "#8b5cf6"}>
            <FaExclamationTriangle />
          </StatIcon>
          <StatInfo>
            <StatValue>{overdueCount}</StatValue>
            <StatLabel>Overdue</StatLabel>
          </StatInfo>
        </StatCard>
      </StatsGrid>

      <Section>
        <SectionTitle>
          <FaTasks /> Recent Tasks
        </SectionTitle>
        <TaskList>
          {tasks.slice(0, 5).map(task => (
            <TaskItem key={task._id}>
              <div style={{ flex: 1 }}>
                <h4>{task.title}</h4>
                <p style={{ fontSize: '14px', color: '#666' }}>
                  {task.project?.name} • Due: {task.dueDate ? format(parseISO(task.dueDate), 'MMM dd') : 'No due date'}
                </p>
              </div>
              <PriorityBadge priority={task.priority}>{task.priority}</PriorityBadge>
              <StatusBadge status={task.status}>{task.status}</StatusBadge>
            </TaskItem>
          ))}
        </TaskList>
        <NavLink to="/tasks">View All Tasks →</NavLink>
      </Section>
    </Container>
  );
};

export default Dashboard;
